[CmdletBinding()]param();$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;. (Join-Path $root 'tests/helpers/TypedStudioFixture.ps1');$work=Join-Path ([IO.Path]::GetTempPath()) ('phase1-'+[guid]::NewGuid().ToString('N'));New-Item -ItemType Directory $work|Out-Null
function Expect([scriptblock]$Action,[string]$Text){try{&$Action;throw 'expected'}catch{if($_.Exception.Message -eq 'expected'){throw};if($_.Exception.Message -notmatch $Text){throw "Expected $Text; got $($_.Exception.Message)"}}}
try{$a=New-TypedStudioFixture $work 'no-approval' -MissingApproval;if(Test-Path (Join-Path $a '.studio/APPROVED_CONCEPT.md')){throw 'MissingApproval created approval'};Expect {& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $a} 'blocked';$blocked=Get-Content -Raw (Join-Path $a '.studio/IMPLEMENTATION_PREFLIGHT.json')|ConvertFrom-Json;if(@($blocked.missingRecords) -notmatch 'APPROVED_CONCEPT.md' -or $blocked.specialistPlanPath){throw 'Missing approval did not produce explicit blocked preflight evidence'};$b=New-TypedStudioFixture $work 'missing-plan' -Approved -MissingRecords @('IMPLEMENTATION_PLAN.md');Remove-Item (Join-Path $b '.studio/IMPLEMENTATION_PLAN.md');Expect {& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $b} 'blocked';$c=New-TypedStudioFixture $work 'valid' -Approved -ExistingRepository;& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $c|Out-Null;$draft=New-TypedStudioFixture $work 'draft' -Approved;$f=Join-Path $draft '.studio/APPROVED_CONCEPT.md';$text=(Get-Content -Raw $f) -replace '"status": "approved"','"status": "draft"';Set-Content $f $text;Expect {& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $draft} 'blocked';$backend=New-TypedStudioFixture $work 'backend-no-approval' -Surfaces @('backend-api') -MissingApproval;Expect {& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $backend} 'blocked';$mixed=New-TypedStudioFixture $work 'mixed-no-approval' -Surfaces @('documentation','backend-api') -MissingApproval;Expect {& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $mixed} 'blocked';$docs=New-TypedStudioFixture $work 'docs' -CurrentState 'discovery' -Surfaces @('documentation') -Runnable:$false;Expect {& "$root/scripts/Test-ImplementationPreflight.ps1" -ProjectRoot $docs} 'blocked';$p=& "$root/scripts/Resolve-SpecialistPlan.ps1" -ProjectRoot (New-TypedStudioFixture $work 'approved-docs' -Surfaces @('documentation') -Approved -Runnable:$false);if($p.selected.Count){throw 'Documentation selected implementation role'};Expect {& "$root/scripts/Initialize-ApprovedProjectRecords.ps1" -ProjectRoot $a} 'valid typed approved concept'}finally{Remove-Item $work -Recurse -Force};Write-Host 'Phase 1 project-state/script integration passed; host-agent and browser runtime unverified.'
